    const second = parseInt((parts.find(p => p.type === 'second') || {}).value || '0', 10);

    const currentMinutes = hour * 60 + minute;
    const start = 4 * 60 + 30;   // 04:30
    const end = 21 * 60 + 30;    // 21:30

    // 如果在服务时间内，返回 null
    if (currentMinutes >= start && currentMinutes <= end) {
        return null;
    }

    let diffSeconds;
    if (currentMinutes < start) {
        // 今天还没到开放时间，目标是今天 04:30
        diffSeconds = (start - currentMinutes) * 60 - second;
    } else {
        // 已经过了今天的开放时间，目标是明天 04:30
        diffSeconds = ((24 * 60 - currentMinutes) + start) * 60 - second;
    }

    const safeDiffSeconds = Math.max(diffSeconds, 0);

    const hours = Math.floor(safeDiffSeconds / 3600);
    const minutes = Math.floor((safeDiffSeconds % 3600) / 60);
    const seconds = safeDiffSeconds % 60;

    return { hours, minutes, seconds };
}

/**
 * 检查是否在服务时间内（英国时间 04:30-21:30）
 */
export function isServiceTimeAvailable() {
    const now = new Date();
    const parts = new Intl.DateTimeFormat('en-GB', {
        timeZone: 'Europe/London',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false
    }).formatToParts(now);

    const ukHour = parseInt((parts.find(p => p.type === 'hour') || {}).value || '0', 10);
    const ukMinute = parseInt((parts.find(p => p.type === 'minute') || {}).value || '0', 10);

    const minutesSinceMidnight = ukHour * 60 + ukMinute;
    const start = 4 * 60 + 30;   // 04:30
    const end = 21 * 60 + 30;    // 21:30

    return minutesSinceMidnight >= start && minutesSinceMidnight <= end;
}

