 * 负责应用状态的集中管理、持久化和恢复
 */

export class StateManager {
    constructor() {
        this.state = {
            // 认证相关
            sessionToken: "",
            phoneNumber: "",
            password: "",

            // eSIM相关
            activationCode: "",
            validationCode: "",

            // 模式控制
            isDeviceChange: false,

            // 步骤控制
            currentStep: 1,

            // 时间戳
            timestamp: 0
        };

        this.listeners = [];
        this.SESSION_KEY = 'simyo_session';
        this.SESSION_TIMEOUT = 5 * 60 * 1000; // 5分钟
    }

    /**
     * 获取完整状态
     */
    getState() {
        return { ...this.state };
    }

    /**
     * 批量更新状态
     */
    setState(updates) {
        this.state = { ...this.state, ...updates };
        this.notifyListeners();
        this.saveSession();
    }

    /**
     * 获取单个状态值
     */
    get(key) {
        return this.state[key];
    }

    /**
     * 设置单个状态值
     */
    set(key, value) {
        this.state[key] = value;
        this.notifyListeners();
        this.saveSession();
    }

    /**
     * 订阅状态变化
     */
    subscribe(listener) {
        this.listeners.push(listener);
        return () => {
            this.listeners = this.listeners.filter(l => l !== listener);
        };
    }

    /**
