  static sanitizeURL(url) {
    if (!url) return '';

    // 移除 javascript:, data:text/html 等危险协议
    const dangerousProtocols = /^(javascript|data:text\/html|vbscript):/i;
    if (dangerousProtocols.test(url)) {
