    const relatedFiles = getRelatedFiles();
    if (relatedFiles.length > 0) {
      steps.push({
        name: `相关测试检查（${relatedFiles.length} 个文件）`,
        args: [
          'test',
          '--',
          '--bail',
          '--findRelatedTests',
          '--passWithNoTests',
          ...relatedFiles
        ]
      });
    } else {
